import{_ as i,o as a,c as o,au as t}from"./chunks/framework.Bpqx6pAq.js";const p=JSON.parse('{"title":"Mixins","description":"","frontmatter":{},"headers":[],"relativePath":"api/core/mixins.md","filePath":"api/core/mixins.md"}'),s={name:"api/core/mixins.md"};function r(l,e,c,n,d,h){return a(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="mixins" tabindex="-1">Mixins <a class="header-anchor" href="#mixins" aria-label="Permalink to &quot;Mixins&quot;">​</a></h1><h2 id="base-activity" tabindex="-1">Base Activity <a class="header-anchor" href="#base-activity" aria-label="Permalink to &quot;Base Activity&quot;">​</a></h2><p>Make it easier to update the application layout when the user changes his current activity.</p><blockquote><p>Causes the activity to be automatically refreshed on user&#39; permissions changes or route change.</p></blockquote><blockquote><p>More details in <a href="./mixins/mixins.base-activity.html">mixins.base-activity</a></p></blockquote><h2 id="base-item" tabindex="-1">Base Item <a class="header-anchor" href="#base-item" aria-label="Permalink to &quot;Base Item&quot;">​</a></h2><p>Make it easier to setup items displayed by a collection.</p><blockquote><p>Causes the item actions to be automatically refreshed on user&#39; permissions changes.</p></blockquote><blockquote><p>More details in <a href="./mixins/mixins.base-item.html">mixins.base-item</a></p></blockquote><h2 id="service" tabindex="-1">Service <a class="header-anchor" href="#service" aria-label="Permalink to &quot;Service&quot;">​</a></h2><p>Make it easier to access an underlying service.</p><blockquote><p>More details in <a href="./mixins/mixins.service.html">mixins.service</a></p></blockquote><h2 id="object-proxy" tabindex="-1">Object Proxy <a class="header-anchor" href="#object-proxy" aria-label="Permalink to &quot;Object Proxy&quot;">​</a></h2><p>Make it easier to access an underlying object of a given service.</p><blockquote><p>More details in <a href="./mixins/mixins.object-proxy.html">mixins.object-proxy</a></p></blockquote><h2 id="schema-proxy" tabindex="-1">Schema Proxy <a class="header-anchor" href="#schema-proxy" aria-label="Permalink to &quot;Schema Proxy&quot;">​</a></h2><p>Make it easier to access an underlying <a href="https://json-schema.org/" target="_blank" rel="noreferrer">JSON schema</a> object for a given service.</p><blockquote><p>More details in <a href="./mixins/mixins.schema-proxy.html">mixins.schema-proxy</a></p></blockquote><h2 id="base-editor" tabindex="-1">Base Editor <a class="header-anchor" href="#base-editor" aria-label="Permalink to &quot;Base Editor&quot;">​</a></h2><p>Make it easier to build <a href="./components.html#editors">editors</a> from props defined on associated mixins. Typically if a JSON schema is directly provided (as a string) it will be parsed, otherwise it will load a schema file which name is computed like this:</p><ul><li>basename is the given schema name or service name</li><li>suffix is <code>.update</code> if the <code>objectId</code> props is defined or <code>.create</code> otherwise</li><li><code>-perspective</code> is added to suffix if the <code>perspective</code> props is defined</li><li>extension is always <code>.json</code></li></ul><p>For instance, if you set props like this <code>&lt;my-editor service=&quot;users&quot;/&gt;</code> on your component using the mixins, the <code>users.create.json</code> schema file will be loaded. If you set props like this <code>&lt;my-editor service=&quot;users&quot; :objectId=&quot;objectId&quot; perspective=&quot;profile&quot;/&gt;</code>, the <code>users.update-profile.json</code> schema file will be loaded.</p><p>Check out a code example <a href="https://github.com/kalisio/kdk/blob/master/core/client/components/editor" target="_blank" rel="noreferrer">here</a> to see how to create your own editors.</p><blockquote><p>More details in <a href="./mixins/mixins.base-editor.html">mixins.base-editor</a></p></blockquote><h2 id="base-viewer" tabindex="-1">Base Viewer <a class="header-anchor" href="#base-viewer" aria-label="Permalink to &quot;Base Viewer&quot;">​</a></h2><p>Make it easier to build <a href="./components.html#viewers">viewers</a> from props defined on associated mixins.</p><blockquote><p>More details in <a href="./mixins/mixins.base-viewer.html">mixins.base-viewer</a></p></blockquote><h2 id="base-field" tabindex="-1">Base Field <a class="header-anchor" href="#base-field" aria-label="Permalink to &quot;Base Field&quot;">​</a></h2><p>Make it easier to build <a href="./components.html#editors">form fields</a>.</p><blockquote><p>More details in <a href="./mixins/mixins.base-field.html">mixins.base-field</a></p></blockquote><p>Check out a code example <a href="https://github.com/kalisio/kdk/blob/master/core/client/components/form" target="_blank" rel="noreferrer">here</a> to see how to create your own fields.</p><h2 id="base-modal" tabindex="-1">Base Modal <a class="header-anchor" href="#base-modal" aria-label="Permalink to &quot;Base Modal&quot;">​</a></h2><p>Make it easier to build <a href="./components.html#modals">modals</a>.</p><blockquote><p>More details in <a href="./mixins/mixins.base-modal.html">mixins.base-modal</a></p></blockquote>',34)])])}const b=i(s,[["render",r]]);export{p as __pageData,b as default};
